import { useState } from "react";
import classes from "./ChatForm.module.css";

const ChatForm = () => {

  return (
    <form id="chat-form" className={classes["form"]}>
      <div className={classes["container"]}>
        <div className={classes["attach"]}>+</div>
  
      </div>
    </form>
  );
};

export default ChatForm;
